settings.custom_liquid:
{% paginate search.results by 8 %}

  <!-- 🔹 Filter + Sort Bar -->
  <div class="filter-sort-bar">

    <!-- Filter by collection tags -->
    <form method="get" action="/search" class="filter-box">
      <input type="hidden" name="q" value="{{ search.terms }}">
      <input type="hidden" name="type" value="product">

      <label for="filter">Filter:</label>
      <select id="filter" name="constraint" onchange="this.form.submit()">
        <option value="">All Products</option>
        {% for tag in collection.all_tags %}
          <option value="{{ tag | handleize }}" 
            {% if current_tags contains tag %}selected{% endif %}>
            {{ tag }}
          </option>
        {% endfor %}
      </select>
    </form>

    <!-- Sort -->
    <form method="get" action="/search" class="sort-box">
      <input type="hidden" name="q" value="{{ search.terms }}">
      <input type="hidden" name="type" value="product">

      <label for="sort-by">Sort by:</label>
      <select id="sort-by" name="sort_by" onchange="this.form.submit()">
        <option value="relevance" {% if search.sort_by == "relevance" %}selected{% endif %}>Relevance</option>
        <option value="price-ascending" {% if search.sort_by == "price-ascending" %}selected{% endif %}>Price, Low to High</option>
        <option value="price-descending" {% if search.sort_by == "price-descending" %}selected{% endif %}>Price, High to Low</option>
        <option value="created-descending" {% if search.sort_by == "created-descending" %}selected{% endif %}>Newest</option>
        <option value="created-ascending" {% if search.sort_by == "created-ascending" %}selected{% endif %}>Oldest</option>
      </select>
    </form>
  </div>

  <!-- 🔹 Product Grid -->
  <div class="product-grid">
    {% for item in search.results %}
      {% if item.object_type == 'product' %}
        <div class="product-card">
          <div class="product-image">
            {% if item.compare_at_price > item.price %}
              <span class="sale-badge">SALE</span>
            {% endif %}
            <a href="{{ item.url }}">
              {{ item.featured_image | image_url: width: 400 | image_tag }}
            </a>
          </div>
          <h3 class="product-title"><a href="{{ item.url }}">{{ item.title }}</a></h3>
          <p class="product-price">
            {% if item.compare_at_price > item.price %}
              <span class="old-price">{{ item.compare_at_price | money }}</span>
            {% endif %}
            <span class="current-price">{{ item.price | money }}</span>
          </p>
        </div>
      {% endif %}
    {% endfor %}
  </div>

  <!-- 🔹 Pagination -->
  <div class="custom-pagination">
    {% if paginate.pages > 1 %}
      <ul>
        {% if paginate.previous %}
          <li><a href="{{ paginate.previous.url }}">&laquo; Prev</a></li>
        {% endif %}
        {% for part in paginate.parts %}
          {% if part.is_link %}
            <li><a href="{{ part.url }}">{{ part.title }}</a></li>
          {% else %}
            <li class="active">{{ part.title }}</li>
          {% endif %}
        {% endfor %}
        {% if paginate.next %}
          <li><a href="{{ paginate.next.url }}">Next &raquo;</a></li>
        {% endif %}
      </ul>
    {% endif %}
  </div>

{% endpaginate %}

settings.custom_css_liquid:
/* Product grid */
.product-grid {
  display: grid;
  grid-template-columns: repeat(4, 1fr); /* 4 per row */
  gap: 20px;
  margin: 20px auto;
  max-width: 1200px; /* optional */
}

.product-card {
  border: 1px solid #ddd;
  padding: 15px;
  text-align: left;
  background: #fff;
  border-radius: 8px;
}

.product-card img {
  width: 100%;
  height: auto;
  border-radius: 0px;
}

.product-title {
  font-size: 15px;
  margin: 10px 0 5px;
}

.product-price {
  font-weight: 500;
}

/* Pagination */
.custom-pagination {
  text-align: center;
  margin-top: 30px;
}
.custom-pagination ul {
  list-style: none;
  display: inline-flex;
  gap: 8px;
  padding: 0;
}
.custom-pagination li {
  border: 1px solid #ddd;
  padding: 6px 12px;
  border-radius: 4px;
}
.custom-pagination li.active {
  background: #000;
  color: #fff;
}
.custom-pagination a {
  text-decoration: none;
  color: #000;
}
.custom-pagination a:hover {
  background: #000;
  color: #fff;
}

.filter-sort-bar {
  display: flex;
  justify-content: space-between; /* pushes filter left, sort right */
  align-items: center;
  margin: 20px 0; /* no auto-centering */
  width: 100%;    /* make it span full width */
  max-width: 1200px; /* optional, only if you want to limit */
}


/* Filter + Sort boxes */
.filter-box,
.sort-box {
  display: flex;
  align-items: center;
  gap: 8px;
}

/* Labels */
.filter-sort-bar label {
  font-weight: bold;
}

/* Dropdowns */
.filter-sort-bar select {
  padding: 6px 10px; /* ✅ Removed padding-left: 80px */
  border: 1px solid #ddd;
  border-radius: 4px;
  background: #fff;
}

@media (max-width: 768px) {
  /* Product grid: 2 per row */
  .product-grid {
    display: grid;
    grid-template-columns: repeat(2, 1fr);
    gap: 12px;
    width: 100%;
  }

  /* Product card */
  .product-card {
    display: flex;
    flex-direction: column;
    height: 100%;
    width: 100%;
    box-sizing: border-box;
    padding: 10px;
    border: 1px solid #ddd;
    border-radius: 8px;
    background: #fff;
  }

  /* Product image wrapper: force same height and crop */
  .product-image {
    width: 100%;
    height: 180px; /* fixed height for all images */
    overflow: hidden;
    border-radius: 6px;
    flex-shrink: 0;
    display: flex;
    justify-content: center;
    align-items: center;
    background: #fff; /* optional, white background */
  }

  .product-image img {
    width: 100%;
    height: 100%;
    object-fit: cover; /* crops image to fill container */
    object-position: center; /* centers the image */
    display: block;
  }

  /* Product title: truncate long text */
  .product-title {
    font-size: 14px;
    margin: 6px 0 4px;
    line-height: 1.3em;
    display: -webkit-box;
    -webkit-line-clamp: 2; /* max 2 lines */
    -webkit-box-orient: vertical;
    overflow: hidden;
  }

  /* Price at bottom */
  .product-price {
    font-size: 13px;
    font-weight: bold;
    margin-top: auto;
  }

  /* Filter + Sort bar */
  .filter-sort-bar {
    flex-wrap: nowrap;
    gap: 6px;
    margin: 10px 0;
    justify-content: space-between;
  }

  .filter-box,
  .sort-box {
    flex: 1 1 auto;
    display: flex;
    align-items: center;
    gap: 4px;
  }

  .filter-sort-bar label {
    font-size: 12px;
    font-weight: 600;
    white-space: nowrap;
  }

  .filter-sort-bar select {
    font-size: 12px;
    padding: 3px 5px;
    min-width: 90px;
    max-width: 110px;
  }

  /* Pagination */
  .custom-pagination ul {
    display: flex;
    flex-wrap: wrap;
    justify-content: center;
    gap: 6px;
  }

  .custom-pagination li {
    padding: 4px 8px;
    font-size: 10px;
    flex-shrink: 0;
  }
}

.product-grid.search-page {
    padding-left: 0 !important;
    padding-right: 0 ! important;
}

